import sys

def main():
    n, m = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(n)]

    # Precompute the first filled cell in each row
    first_filled = [m] * n
    for y in range(n):
        for x in range(m):
            if grid[y][x] == 'X':
                first_filled[y] = x
                break

    # Precompute the prefix sums for the first filled cells
    prefix = [0] * (m + 1)
    for y in range(n):
        if first_filled[y] < m:
            prefix[first_filled[y]] += 1
    for x in range(1, m + 1):
        prefix[x] += prefix[x - 1]

    q = int(sys.stdin.readline())
    for _ in range(q):
        x1, x2 = map(int, sys.stdin.readline().split())
        x1 -= 1
        x2 -= 1
        # Check if all rows have their first filled cell >= x2 + 1
        if prefix[x2] == prefix[m]:
            print("YES")
        else:
            print("NO")

if __name__ == "__main__":
    main()

